@dataclass
class Dependency:
    """Represents a single dependency."""
    name: str
    version_spec: str = ""  # e.g., ">=1.0,<2.0" or "==1.2.3"
    pinned_version: str = ""  # e.g., "1.2.3"
    hashes: List[str] = field(default_factory=list)
    group: DependencyGroup = DependencyGroup.MAIN
    extras: List[str] = field(default_factory=list)
    markers: str = ""  # environment markers like 'python_version >= "3.8"'
    is_direct: bool = True  # True if explicitly requested, False if transitive

    def to_requirements_line(self, include_hashes: bool = True) -> str:
        """Format as a requirements.txt line."""
        parts = [self.name]
        if self.extras:
            parts[0] = f"{self.name}[{','.join(self.extras)}]"
        if self.pinned_version:
            parts.append(f"=={self.pinned_version}")
        elif self.version_spec:
            parts.append(self.version_spec)
        if self.markers:
            parts.append(f"; {self.markers}")
        line = "".join(parts)
        if include_hashes and self.hashes:
            hash_lines = " \\\n".join(f"    --hash={h}" for h in self.hashes)
            line = f"{line} \\\n{hash_lines}"
        return line


