    project_name: str = ""
    generate_hashes: bool = True
    allow_unsafe: bool = False
    trusted_hosts: List[str] = field(default_factory=list)
    extra_index_urls: List[str] = field(default_factory=list)
    pre_release: bool = False
    groups: Dict[str, List[str]] = field(default_factory=dict)

    def to_dict(self) -> dict:
        return {
            "backend": self.backend.value,
            "python_version": self.python_version,
            "project_name": self.project_name,
            "generate_hashes": self.generate_hashes,
            "allow_unsafe": self.allow_unsafe,
            "trusted_hosts": self.trusted_hosts,
            "extra_index_urls": self.extra_index_urls,
            "pre_release": self.pre_release,
            "groups": self.groups,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "ProjectConfig":
        config = cls()
        config.backend = Backend(data.get("backend", "pip-tools"))
        config.python_version = data.get("python_version", "")
        config.project_name = data.get("project_name", "")
        config.generate_hashes = data.get("generate_hashes", True)
        config.allow_unsafe = data.get("allow_unsafe", False)
        config.trusted_hosts = data.get("trusted_hosts", [])
        config.extra_index_urls = data.get("extra_index_urls", [])
        config.pre_release = data.get("pre_release", False)
        config.groups = data.get("groups", {})
        return config


