def run_command(
    cmd: List[str],
    capture_output: bool = True,
    check: bool = True,
    cwd: Optional[str] = None,
) -> subprocess.CompletedProcess:
    """Run a shell command with error handling."""
    print(f"  → Running: {' '.join(cmd)}")
    try:
        result = subprocess.run(
            cmd,
            capture_output=capture_output,
            text=True,
            check=check,
            cwd=cwd,
        )
        return result
    except subprocess.CalledProcessError as e:
        print(f"  ✗ Command failed with exit code {e.returncode}")
        if e.stdout:
            print(f"  stdout: {e.stdout[:500]}")
        if e.stderr:
            print(f"  stderr: {e.stderr[:500]}")
        raise
    except FileNotFoundError:
        print(f"  ✗ Command not found: {cmd[0]}")
        print(f"    Install it with: pip install {cmd[0]}")
        raise


def compute_file_hash(filepath: Path) -> str:
    """Compute SHA256 hash of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def check_tool_available(tool: str) -> bool:
    """Check if a CLI tool is available."""
    return shutil.which(tool) is not None


def get_python_version() -> str:
    """Get the current Python version string."""
    return f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"


def get_platform_info() -> str:
    """Get current platform information."""
    import platform
    return f"{platform.system()}-{platform.machine()}"


def load_config(project_dir: Path) -> ProjectConfig:
    """Load project configuration from config file."""
    config_path = project_dir / CONFIG_FILE
    if config_path.exists():
        with open(config_path) as f:
            data = json.load(f)
        return ProjectConfig.from_dict(data)
    return ProjectConfig()


def save_config(project_dir: Path, config: ProjectConfig):
    """Save project configuration to config file."""
    config_path = project_dir / CONFIG_FILE
    with open(config_path, "w") as f:
        json.dump(config.to_dict(), f, indent=2)
    print(f"  ✓ Configuration saved to {config_path}")


def generate_lock_header(config: ProjectConfig) -> str:
    """Generate a header comment for lock files."""
    return textwrap.dedent(f"""\
        #
        # This file is autogenerated by dependency_manager.py
        # Do not edit manually. Run 'python dependency_manager.py lock' to regenerate.
        #
        # Generated at: {datetime.utcnow().isoformat()}Z
        # Python version: {get_python_version()}
        # Platform: {get_platform_info()}
        # Backend: {config.backend.value}
        #
    """)


def parse_requirements_file(filepath: Path) -> List[Dependency]:
    """Parse a requirements.txt or .in file into Dependency objects."""
    dependencies = []
    if not filepath.exists():
        return dependencies

    with open(filepath) as f:
        lines = f.readlines()

    current_dep = None
    for line in lines:
        line = line.strip()
        # Skip comments and empty lines
        if not line or line.startswith("#"):
            continue
        # Skip options like --hash, -r, -c, --index-url etc.
        if line.startswith("-") and not line.startswith("--hash"):
            continue

        # Handle continuation lines (hashes)
        if line.startswith("--hash=") and current_dep:
            current_dep.hashes.append(line.replace("--hash=", ""))
            continue

        # Remove inline comments
        if " #" in line:
            line = line[:line.index(" #")]

        # Remove trailing backslash (continuation)
        line = line.rstrip("\\").strip()

        if not line:
            continue

        # Parse the dependency specification
        dep = _parse_requirement_line(line)
        if dep:
            if current_dep:
                dependencies.append(current_dep)
            current_dep = dep

    if current_dep:
        dependencies.append(current_dep)

    return dependencies


def _parse_requirement_line(line: str) -> Optional[Dependency]:
    """Parse a single requirement line into a Dependency object."""
    # Pattern: package[extras]version_spec; markers
    pattern = r'^([a-zA-Z0-9_.-]+)(?:\[([^\]]+)\])?\s*((?:[><=!~]=?[^;]*)?)\s*(?:;\s*(.+))?$'
    match = re.match(pattern, line.strip())
    if not match:
        return None

    name = match.group(1)
    extras = match.group(2).split(",") if match.group(2) else []
    version_spec = match.group(3).strip() if match.group(3) else ""
    markers = match.group(4).strip() if match.group(4) else ""

    # Extract pinned version if exact
    pinned = ""
    if version_spec.startswith("=="):
        pinned = version_spec[2:].strip()

    return Dependency(
        name=name,
        version_spec=version_spec,
        pinned_version=pinned,
        extras=extras,
        markers=markers,
    )


