class PipToolsBackend:
    """
    Manages dependencies using pip-tools (pip-compile and pip-sync).

    Workflow:
        1. Define loose requirements in .in files (e.g., requirements.in)
        2. Run pip-compile to generate locked .txt files with pinned versions and hashes
        3. Run pip-sync to install exactly what's in the lock file

    File Structure:
        requirements.in          → Direct production dependencies (loose)
        requirements.txt         → Locked production dependencies (generated)
        requirements-dev.in      → Direct dev dependencies (loose)
        requirements-dev.txt     → Locked dev dependencies (generated)
        requirements-test.in     → Direct test dependencies (loose)
        requirements-test.txt    → Locked test dependencies (generated)
    """

    def __init__(self, project_dir: Path, config: ProjectConfig):
        self.project_dir = project_dir
        self.config = config

    def ensure_tools(self):
        """Ensure pip-tools is installed."""
        if not check_tool_available("pip-compile"):
            print("  Installing pip-tools...")
            run_command([sys.executable, "-m", "pip", "install", "pip-tools"])

    def init(self):
        """Initialize pip-tools project structure."""
        self.ensure_tools()
        print("\n📁 Initializing pip-tools project structure...")

        # Create source .in files with example content
        templates = {
            DependencyGroup.MAIN: textwrap.dedent("""\
                # Production dependencies
                # Add your production dependencies here with loose version constraints.
                # Run 'python dependency_manager.py lock' to generate the lock file.
                #
                # Examples:
                # requests>=2.28,<3.0
                # django>=4.2,<5.0
                # psycopg2-binary>=2.9
            """),
            DependencyGroup.DEV: textwrap.dedent("""\
                # Development dependencies
                # These are only needed during development.
                #
                # Include production deps:
                -r requirements.in
                #
                # Dev tools:
                # black>=23.0
                # ruff>=0.1.0
                # mypy>=1.0
                # ipython>=8.0
                # pre-commit>=3.0
            """),
            DependencyGroup.TEST: textwrap.dedent("""\
                # Test dependencies
                # These are needed for running the test suite.
                #
                # Include production deps:
                -r requirements.in
                #
                # Test tools:
                # pytest>=7.0
                # pytest-cov>=4.0
                # pytest-mock>=3.0
                # factory-boy>=3.0
                # faker>=18.0
            """),
        }

        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        for group, template in templates.items():
            filepath = self.project_dir / source_files[group]
            if not filepath.exists():
                filepath.write_text(template)
                print(f"  ✓ Created {filepath}")
            else:
                print(f"  ⏭ {filepath} already exists, skipping")

    def lock(self, groups: Optional[List[DependencyGroup]] = None):
        """Generate lock files from .in source files."""
        self.ensure_tools()
        print("\n🔒 Generating lock files with pip-compile...")

        if groups is None:
            groups = [DependencyGroup.MAIN, DependencyGroup.DEV, DependencyGroup.TEST]

        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        lock_files = LOCK_FILES[Backend.PIP_TOOLS]

        for group in groups:
            source = self.project_dir / source_files[group]
            output = self.project_dir / lock_files[group]

            if not source.exists():
                print(f"  ⏭ Source file {source} not found, skipping {group.value}")
                continue

            print(f"\n  Compiling {source.name} → {output.name}...")

            cmd = [
                "pip-compile",
                str(source),
                "--output-file", str(output),
                "--strip-extras",  # Remove extras from output
                "--no-header",  # We add our own header
            ]

            if self.config.generate_hashes:
                cmd.append("--generate-hashes")

            if self.config.allow_unsafe:
                cmd.append("--allow-unsafe")

            if self.config.pre_release:
                cmd.append("--pre")

            for index_url in self.config.extra_index_urls:
                cmd.extend(["--extra-index-url", index_url])

            for host in self.config.trusted_hosts:
                cmd.extend(["--trusted-host", host])

            try:
                run_command(cmd)

                # Prepend our header to the generated file
                if output.exists():
                    content = output.read_text()
                    header = generate_lock_header(self.config)
                    output.write_text(header + content)

                print(f"  ✓ Generated {output}")
                self._print_lock_summary(output)
            except subprocess.CalledProcessError:
                print(f"  ✗ Failed to compile {source.name}")

    def update(self, package: Optional[str] = None, groups: Optional[List[DependencyGroup]] = None):
        """Update lock files, optionally for a specific package."""
        self.ensure_tools()

        if groups is None:
            groups = [DependencyGroup.MAIN, DependencyGroup.DEV, DependencyGroup.TEST]

        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        lock_files = LOCK_FILES[Backend.PIP_TOOLS]

        for group in groups:
            source = self.project_dir / source_files[group]
            output = self.project_dir / lock_files[group]

            if not source.exists():
                continue

            if package:
                print(f"\n📦 Updating {package} in {output.name}...")
            else:
                print(f"\n🔄 Updating all packages in {output.name}...")

            cmd = [
                "pip-compile",
                "--upgrade",
                str(source),
                "--output-file", str(output),
                "--strip-extras",
                "--no-header",
            ]

            if package:
                cmd.extend(["--upgrade-package", package])

            if self.config.generate_hashes:
                cmd.append("--generate-hashes")

            if self.config.allow_unsafe:
                cmd.append("--allow-unsafe")

            try:
                run_command(cmd)

                if output.exists():
                    content = output.read_text()
                    header = generate_lock_header(self.config)
                    output.write_text(header + content)

                print(f"  ✓ Updated {output}")
                self._print_lock_summary(output)
            except subprocess.CalledProcessError:
                print(f"  ✗ Failed to update {output.name}")

    def install(self, groups: Optional[List[DependencyGroup]] = None):
        """Install dependencies from lock files using pip-sync."""
        self.ensure_tools()

        if groups is None:
            groups = [DependencyGroup.MAIN]

        lock_files_map = LOCK_FILES[Backend.PIP_TOOLS]
        files_to_sync = []

        for group in groups:
            lock_file = self.project_dir / lock_files_map[group]
            if lock_file.exists():
                files_to_sync.append(str(lock_file))
            else:
                print(f"  ⚠ Lock file {lock_file} not found for group '{group.value}'")

        if not files_to_sync:
            print("  ✗ No lock files found. Run 'lock' first.")
            return

        print(f"\n📥 Installing dependencies from: {', '.join(files_to_sync)}")

        cmd = ["pip-sync"] + files_to_sync
        try:
            run_command(cmd)
            print("  ✓ Dependencies installed successfully")
        except subprocess.CalledProcessError:
            print("  ✗ Failed to sync dependencies")
            print("  Try: pip install -r " + " -r ".join(files_to_sync))

    def add(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Add a dependency to a source file and regenerate lock."""
        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        source = self.project_dir / source_files[group]

        if not source.exists():
            source.write_text(f"# {group.value} dependencies\n")

        # Check if already present
        existing = parse_requirements_file(source)
        pkg_name = re.split(r'[><=!~\[]', package)[0].strip().lower()
        for dep in existing:
            if dep.name.lower() == pkg_name:
                print(f"  ⚠ {pkg_name} already in {source.name}, updating...")
                # Remove old entry
                lines = source.read_text().splitlines()
                new_lines = [l for l in lines if not l.strip().lower().startswith(pkg_name)]
                source.write_text("\n".join(new_lines) + "\n")
                break

        # Append the new dependency
        with open(source, "a") as f:
            f.write(f"{package}\n")
        print(f"  ✓ Added {package} to {source.name}")

        # Regenerate lock file
        self.lock(groups=[group])

    def remove(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Remove a dependency from a source file and regenerate lock."""
        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        source = self.project_dir / source_files[group]

        if not source.exists():
            print(f"  ✗ Source file {source} not found")
            return

        pkg_name = package.strip().lower()
        lines = source.read_text().splitlines()
        new_lines = []
        removed = False

        for line in lines:
            stripped = line.strip().lower()
            if stripped and not stripped.startswith("#") and not stripped.startswith("-"):
                line_pkg = re.split(r'[><=!~\[]', stripped)[0].strip()
                if line_pkg == pkg_name:
                    removed = True
                    continue
            new_lines.append(line)

        if removed:
            source.write_text("\n".join(new_lines) + "\n")
            print(f"  ✓ Removed {package} from {source.name}")
            self.lock(groups=[group])
        else:
            print(f"  ⚠ {package} not found in {source.name}")

    def verify(self) -> bool:
        """Verify that lock files are up-to-date with source files."""
        print("\n🔍 Verifying lock file consistency...")
        all_ok = True

        source_files = SOURCE_FILES[Backend.PIP_TOOLS]
        lock_files_map = LOCK_FILES[Backend.PIP_TOOLS]

        for group in [DependencyGroup.MAIN, DependencyGroup.DEV, DependencyGroup.TEST]:
            source = self.project_dir / source_files[group]
            lock_file = self.project_dir / lock_files_map[group]

            if not source.exists():
                continue

            if not lock_file.exists():
                print(f"  ✗ Lock file {lock_file.name} missing for {source.name}")
                all_ok = False
                continue

            # Try a dry-run compile to check if lock is current
            with tempfile.NamedTemporaryFile(mode="w", suffix=".txt", delete=False) as tmp:
                tmp_path = tmp.name

            try:
                cmd = [
                    "pip-compile",
                    str(source),
                    "--output-file", tmp_path,
                    "--strip-extras",
                    "--no-header",
                    "--quiet",
                ]
                if self.config.generate_hashes:
                    cmd.append("--generate-hashes")
                if self.config.allow_unsafe:
                    cmd.append("--allow-unsafe")

                run_command(cmd)

                # Compare (ignoring headers/comments)
                def strip_comments(text):
                    return "\n".join(
                        l for l in text.splitlines()
                        if l.strip() and not l.strip().startswith("#")
                    )

                current = strip_comments(lock_file.read_text())
                fresh = strip_comments(Path(tmp_path).read_text())

                if current == fresh:
                    print(f"  ✓ {lock_file.name} is up-to-date with {source.name}")
                else:
                    print(f"  ✗ {lock_file.name} is OUT OF DATE with {source.name}")
                    print(f"    Run 'python dependency_manager.py lock' to update")
                    all_ok = False
            except subprocess.CalledProcessError:
                print(f"  ✗ Failed to verify {lock_file.name}")
                all_ok = False
            finally:
                os.unlink(tmp_path)

        return all_ok

    def _print_lock_summary(self, lock_file: Path):
        """Print a summary of a lock file."""
        if not lock_file.exists():
            return
        deps = parse_requirements_file(lock_file)
        print(f"    📊 {len(deps)} packages locked")


