class PoetryBackend:
    """
    Manages dependencies using Poetry.

    Workflow:
        1. Define dependencies in pyproject.toml
        2. Run poetry lock to generate poetry.lock
        3. Run poetry install to install from lock file

    File Structure:
        pyproject.toml    → Project metadata and dependency specs
        poetry.lock       → Locked dependency versions (generated)
    """

    def __init__(self, project_dir: Path, config: ProjectConfig):
        self.project_dir = project_dir
        self.config = config

    def ensure_tools(self):
        """Ensure Poetry is installed."""
        if not check_tool_available("poetry"):
            print("  Poetry not found. Install it:")
            print("    curl -sSL https://install.python-poetry.org | python3 -")
            print("  Or: pip install poetry")
            raise RuntimeError("Poetry is not installed")

    def init(self):
        """Initialize a Poetry project."""
        self.ensure_tools()
        print("\n📁 Initializing Poetry project...")

        pyproject = self.project_dir / "pyproject.toml"
        if pyproject.exists():
            print(f"  ⏭ {pyproject} already exists")
            return

        # Generate a basic pyproject.toml
        project_name = self.config.project_name or self.project_dir.name
        template = textwrap.dedent(f"""\
            [tool.poetry]
            name = "{project_name}"
            version = "0.1.0"
            description = "A Python project with managed dependencies"
            authors = ["Team <team@example.com>"]
            readme = "README.md"

            [tool.poetry.dependencies]
            python = "^{sys.version_info.major}.{sys.version_info.minor}"
            # Add production dependencies here:
            # requests = "^2.28"
            # django = "^4.2"

            [tool.poetry.group.dev.dependencies]
            # Add development dependencies here:
            # black = "^23.0"
            # ruff = "^0.1"
            # mypy = "^1.0"
            # ipython = "^8.0"

            [tool.poetry.group.test.dependencies]
            # Add test dependencies here:
            # pytest = "^7.0"
            # pytest-cov = "^4.0"
            # pytest-mock = "^3.0"

            [build-system]
            requires = ["poetry-core"]
            build-backend = "poetry.core.masonry.api"

            # Poetry configuration
            [tool.poetry.scripts]
            # entry-point-name = "package.module:function"
        """)

        pyproject.write_text(template)
        print(f"  ✓ Created {pyproject}")
        print("  Edit pyproject.toml to add your dependencies, then run 'lock'")

    def lock(self, groups: Optional[List[DependencyGroup]] = None):
        """Generate poetry.lock from pyproject.toml."""
        self.ensure_tools()
        print("\n🔒 Generating poetry.lock...")

        cmd = ["poetry", "lock"]
        try:
            run_command(cmd, cwd=str(self.project_dir))
            lock_file = self.project_dir / "poetry.lock"
            if lock_file.exists():
                print(f"  ✓ Generated {lock_file}")
        except subprocess.CalledProcessError:
            print("  ✗ Failed to generate lock file")

    def update(self, package: Optional[str] = None, groups: Optional[List[DependencyGroup]] = None):
        """Update dependencies in poetry.lock."""
        self.ensure_tools()

        if package:
            print(f"\n📦 Updating {package}...")
            cmd = ["poetry", "update", package]
        else:
            print("\n🔄 Updating all dependencies...")
            cmd = ["poetry", "update"]

        try:
            run_command(cmd, cwd=str(self.project_dir))
            print("  ✓ Dependencies updated")
        except subprocess.CalledProcessError:
            print("  ✗ Failed to update dependencies")

    def install(self, groups: Optional[List[DependencyGroup]] = None):
        """Install dependencies from poetry.lock."""
        self.ensure_tools()
        print("\n📥 Installing dependencies with Poetry...")

        cmd = ["poetry", "install"]

        if groups:
            group_names = [g.value for g in groups if g != DependencyGroup.MAIN]
            if DependencyGroup.MAIN in groups and len(groups) == 1:
                cmd.extend(["--only", "main"])
            else:
                for group_name in group_names:
                    cmd.extend(["--with", group_name])

        try:
            run_command(cmd, cwd=str(self.project_dir))
            print("  ✓ Dependencies installed")
        except subprocess.CalledProcessError:
            print("  ✗ Failed to install dependencies")

    def add(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Add a dependency using poetry add."""
        self.ensure_tools()

        cmd = ["poetry", "add", package]
        if group != DependencyGroup.MAIN:
            cmd.extend(["--group", group.value])

        print(f"\n➕ Adding {package} to {group.value} group...")
        try:
            run_command(cmd, cwd=str(self.project_dir))
            print(f"  ✓ Added {package}")
        except subprocess.CalledProcessError:
            print(f"  ✗ Failed to add {package}")

    def remove(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Remove a dependency using poetry remove."""
        self.ensure_tools()

        cmd = ["poetry", "remove", package]
        if group != DependencyGroup.MAIN:
            cmd.extend(["--group", group.value])

        print(f"\n➖ Removing {package} from {group.value} group...")
        try:
            run_command(cmd, cwd=str(self.project_dir))
            print(f"  ✓ Removed {package}")
        except subprocess.CalledProcessError:
            print(f"  ✗ Failed to remove {package}")

    def verify(self) -> bool:
        """Verify poetry.lock is consistent with pyproject.toml."""
        self.ensure_tools()
        print("\n🔍 Verifying lock file consistency...")

        cmd = ["poetry", "check", "--lock"]
        try:
            result = run_command(cmd, cwd=str(self.project_dir), check=False)
            if result.returncode == 0:
                print("  ✓ poetry.lock is consistent with pyproject.toml")
                return True
            else:
                print("  ✗ poetry.lock is OUT OF DATE")
                print("    Run 'python dependency_manager.py lock' to update")
                return False
        except Exception:
            print("  ✗ Failed to verify lock file")
            return False

    def export(self, output_file: Optional[str] = None, group: DependencyGroup = DependencyGroup.MAIN):
        """Export poetry.lock to requirements.txt format."""
        self.ensure_tools()
        output = output_file or "requirements.txt"
        print(f"\n📤 Exporting to {output}...")

        cmd = [
            "poetry", "export",
            "-f", "requirements.txt",
            "--output", output,
        ]

        if self.config.generate_hashes:
            # Poetry export includes hashes by default in newer versions
            pass
        else:
            cmd.append("--without-hashes")

        if group != DependencyGroup.MAIN:
            cmd.extend(["--with", group.value])

        try:
            run_command(cmd, cwd=str(self.project_dir))
            print(f"  ✓ Exported to {output}")
        except subprocess.CalledProcessError:
            print(f"  ✗ Failed to export")
            print("  You may need: poetry self add poetry-plugin-export")


# ============================================================================
# Backend: Plain pip (with manual hash generation)
# ============================================================================

class PipBackend:
    """
    Manages dependencies using plain pip with manual locking.

    This is a simpler approach for projects that don't want additional tools.
    It uses pip freeze to capture exact versions and can fetch hashes from PyPI.

    Workflow:
        1. Define loose requirements in .in files
        2. Install them in a clean venv
        3. Freeze the result with hashes
    """

    def __init__(self, project_dir: Path, config: ProjectConfig):
        self.project_dir = project_dir
        self.config = config

    def init(self):
        """Initialize pip-based project structure."""
        print("\n📁 Initializing pip project structure...")

        source_file = self.project_dir / "requirements.in"
        if not source_file.exists():
            source_file.write_text(textwrap.dedent("""\
                # Production dependencies
                # Add loose version constraints here.
                # Run 'python dependency_manager.py lock' to generate requirements.txt
                #
                # Example:
                # requests>=2.28,<3.0
            """))
            print(f"  ✓ Created {source_file}")

        dev_file = self.project_dir / "requirements-dev.in"
        if not dev_file.exists():
            dev_file.write_text(textwrap.dedent("""\
                # Development dependencies
                -r requirements.in
                #
                # Example:
                # black>=23.0
                # pytest>=7.0
            """))
            print(f"  ✓ Created {dev_file}")

    def lock(self, groups: Optional[List[DependencyGroup]] = None):
        """Generate locked requirements files."""
        print("\n🔒 Generating lock files with pip freeze...")
        print("  ⚠ For best results, consider using pip-tools backend instead.")

        if groups is None:
            groups = [DependencyGroup.MAIN]

        source_files = SOURCE_FILES[Backend.PIP]
        lock_files_map = LOCK_FILES[Backend.PIP]

        for group in groups:
            source = self.project_dir / source_files[group]
            output = self.project_dir / lock_files_map[group]

            if not source.exists():
                continue

            print(f"\n  Locking {source.name} → {output.name}...")

            # Create a temporary venv, install, and freeze
            with tempfile.TemporaryDirectory() as tmpdir:
                venv_dir = Path(tmpdir) / "venv"
                pip_path = venv_dir / ("Scripts" if os.name == "nt" else "bin") / "pip"

                # Create venv
                run_command([sys.executable, "-m", "venv", str(venv_dir)])

                # Install from source
                run_command([str(pip_path), "install", "-r", str(source)])

                # Freeze
                result = run_command([str(pip_path), "freeze"])

                # Parse frozen output and optionally fetch hashes
                frozen_lines = result.stdout.strip().splitlines()
                header = generate_lock_header(self.config)

                output_lines = [header]
                for line in frozen_lines:
                    if self.config.generate_hashes and "==" in line:
                        hashes = self._fetch_hashes(line)
                        if hashes:
                            hash_str = " \\\n".join(f"    --hash={h}" for h in hashes)
                            output_lines.append(f"{line} \\\n{hash_str}")
                        else:
                            output_lines.append(line)
                    else:
                        output_lines.append(line)

                output.write_text("\n".join(output_lines) + "\n")
                print(f"  ✓ Generated {output}")

    def _fetch_hashes(self, requirement: str) -> List[str]:
        """Fetch package hashes from PyPI."""
        try:
            name, version = requirement.split("==")
            name = name.strip()
            version = version.strip()
            url = f"https://pypi.org/pypi/{name}/{version}/json"
            with urlopen(url, timeout=10) as response:
                data = json.loads(response.read())
                hashes = []
                for file_info in data.get("urls", []):
                    digests = file_info.get("digests", {})
                    if "sha256" in digests:
                        hashes.append(f"sha256:{digests['sha256']}")
                return hashes
        except (URLError, json.JSONDecodeError, ValueError, KeyError):
            return []

    def update(self, package: Optional[str] = None, groups: Optional[List[DependencyGroup]] = None):
        """Update dependencies by regenerating lock files."""
        print("\n🔄 Regenerating lock files...")
        self.lock(groups=groups)

    def install(self, groups: Optional[List[DependencyGroup]] = None):
        """Install from lock files."""
        if groups is None:
            groups = [DependencyGroup.MAIN]

        lock_files_map = LOCK_FILES[Backend.PIP]

        for group in groups:
            lock_file = self.project_dir / lock_files_map[group]
            if not lock_file.exists():
                print(f"  ⚠ {lock_file} not found")
                continue

            print(f"\n📥 Installing from {lock_file.name}...")
            cmd = [sys.executable, "-m", "pip", "install", "-r", str(lock_file)]

            if self.config.generate_hashes:
                cmd.append("--require-hashes")

            try:
                run_command(cmd)
                print(f"  ✓ Installed from {lock_file.name}")
            except subprocess.CalledProcessError:
                print(f"  ✗ Failed to install from {lock_file.name}")

    def add(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Add a dependency."""
        source_files = SOURCE_FILES[Backend.PIP]
        source = self.project_dir / source_files[group]

        if not source.exists():
            source.write_text(f"# {group.value} dependencies\n")

        with open(source, "a") as f:
            f.write(f"{package}\n")
        print(f"  ✓ Added {package} to {source.name}")
        self.lock(groups=[group])

    def remove(self, package: str, group: DependencyGroup = DependencyGroup.MAIN):
        """Remove a dependency."""
        source_files = SOURCE_FILES[Backend.PIP]
        source = self.project_dir / source_files[group]

        if not source.exists():
            print(f"  ✗ {source} not found")
            return

        pkg_name = package.strip().lower()
        lines = source.read_text().splitlines()
        new_lines = []
        removed = False

        for line in lines:
            stripped = line.strip().lower()
            if stripped and not stripped.startswith("#") and not stripped.startswith("-"):
                line_pkg = re.split(r'[><=!~\[]', stripped)[0].strip()
                if line_pkg == pkg_name:
                    removed = True
                    continue
            new_lines.append(line)

        if removed:
            source.write_text("\n".join(new_lines) + "\n")
            print(f"  ✓ Removed {package}")
            self.lock(groups=[group])
        else:
            print(f"  ⚠ {package} not found in {source.name}")

    def verify(self) -> bool:
        """Basic verification of lock files."""
        print("\n🔍 Verifying lock files exist...")
        all_ok = True
        lock_files_map = LOCK_FILES[Backend.PIP]
        source_files = SOURCE_FILES[Backend.PIP]

        for group in [DependencyGroup.MAIN, DependencyGroup.DEV, DependencyGroup.TEST]:
            source = self.project_dir / source_files[group]
            lock_file = self.project_dir / lock_files_map[group]

            if source.exists() and not lock_file.exists():
                print(f"  ✗ {lock_file.name} missing (source: {source.name})")
                all_ok = False
            elif source.exists() and lock_file.exists():
                # Check if source is newer than lock
                source_mtime = source.stat().st_mtime
                lock_mtime = lock_file.stat().st_mtime
                if source_mtime > lock_mtime:
                    print(f"  ⚠ {source.name} is newer than {lock_file.name}")
                    all_ok = False
                else:
                    print(f"  ✓ {lock_file.name} appears up-to-date")

        return all_ok


# ============================================================================
# Dependency Auditing
# ============================================================================

class DependencyAuditor:
    """
    Audits dependencies for known vulnerabilities and best practices.

    Uses:
    - pip-audit for vulnerability scanning
    - Safety (optional) for additional vulnerability database
    - Custom checks for best practices
    """

    def __init__(self, project_dir: Path, config: ProjectConfig):
        self.project_dir = project_dir
        self.config = config

    def audit(self):
        """Run a full dependency audit."""
        print("\n🛡️  Running dependency audit...")
        print("=" * 60)

        # 1. Check for pip-audit
        self._run_pip_audit()

        # 2. Check for outdated packages
        self._check_outdated()

        # 3. Custom best practice checks
        self._check_best_practices()

        print("\n" + "=" * 60)
        print("Audit complete.")

    def _run_pip_audit(self):
        """Run pip-audit for vulnerability scanning."""
        print("\n📋 Vulnerability Scan (pip-audit):")

        if not check_tool_available("pip-audit"):
            print("  ⚠ pip-audit not installed. Install with: pip install pip-audit")
            print("  Attempting to run anyway...")
            try:
                run_command([sys.executable, "-m", "pip", "install", "pip-audit"])
            except subprocess.CalledProcessError:
                print("  ✗ Could not install pip-audit, skipping vulnerability scan")
                return

        lock_files = LOCK_FILES.get(self.config.backend, {})
        main_lock = lock_files.get(DependencyGroup.MAIN)

        if main_lock:
            lock_path = self.project_dir / main_lock
            if lock_path.exists():
                cmd = ["pip-audit", "-r", str(lock_path)]
                if not self.config.generate_hashes:
                    cmd.append("--no-deps")  # Avoid hash issues
                try:
                    result = run_command(cmd, check=False)
                    if result.returncode == 0:
                        print("  ✓ No known vulnerabilities found")
                    else:
                        print("  ⚠ Vulnerabilities detected! Review output above.")
                except FileNotFoundError:
                    print("  ✗ pip-audit not available")
            else:
                print(f"  ⏭ Lock file {lock_path} not found")

    def _check_outdated(self):
        """Check for outdated packages."""
        print("\n📋 Outdated Packages:")
        try:
            result = run_command(
                [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
                check=False,
            )
            if result.returncode == 0 and result.stdout:
                outdated = json.loads(result.stdout)
                if outdated:
                    for pkg in outdated[:20]:  # Show top 20
                        print(
                            f"  📦 {pkg['name']}: "
                            f"{pkg['version']} → {pkg['latest_version']} "
                            f"({pkg.get('latest_filetype', 'unknown')})"
                        )
                    if len(outdated) > 20:
                        print(f"  ... and {len(outdated) - 20} more")
                else:
                    print("  ✓ All packages are up-to-date")
        except (subprocess.CalledProcessError, json.JSONDecodeError):
            print("  ✗ Could not check for outdated packages")

    def _check_best_practices(self):
        """Check for dependency management best practices."""
        print("\n📋 Best Practice Checks:")
        issues = []

        # Check: Lock files exist
        lock_files = LOCK_FILES.get(self.config.backend, {})
        main_lock = lock_files.get(DependencyGroup.MAIN)
        if main_lock:
            lock_path = self.project_dir / main_lock
            if not lock_path.exists():
                issues.append("Lock file missing. Run 'lock' to generate.")

        # Check: Hashes enabled
        if not self.config.generate_hashes:
            issues.append(
                "Hash verification disabled. Enable for supply-chain security."
            )

        # Check: .gitignore includes venv but not lock files
        gitignore = self.project_dir / ".gitignore"
        if gitignore.exists():
            content = gitignore.read_text()
            if "requirements.txt" in content and self.config.backend == Backend.PIP_TOOLS:
                issues.append(
                    "requirements.txt appears in .gitignore. "
                    "Lock files should be committed to version control!"
                )
            if "poetry.lock" in content and self.config.backend == Backend.POETRY:
                issues.append(
                    "poetry.lock appears in .gitignore. "
                    "Lock files should be committed to version control!"
                )

        # Check: Source files have version constraints
        source_files = SOURCE_FILES.get(self.config.backend, {})
        main_source = source_files.get(DependencyGroup.MAIN)
        if main_source:
            source_path = self.project_dir / main_source
            if source_path.exists():
                deps = parse_requirements_file(source_path)
                unconstrained = [d for d in deps if not d.version_spec]
                if unconstrained:
                    names = ", ".join(d.name for d in unconstrained[:5])
                    issues.append(
                        f"Unconstrained dependencies found: {names}. "
                        "Add version constraints (e.g., '>=1.0,<2.0')."
                    )

        if issues:
            for issue in issues:
                print(f"  ⚠ {issue}")
        else:
            print("  ✓ All best practice checks passed")


# ============================================================================
# Dependency Tree Viewer
# ============================================================================

class DependencyTreeViewer:
    """Displays the dependency tree for the current environment."""

    def __init__(self, project_dir: Path):
        self.project_dir = project_dir

    def show_tree(self):
        """Display the dependency tree using pipdeptree or pip."""
        print("\n🌳 Dependency Tree:")
        print("=" * 60)

        # Try pipdeptree first
        if check_tool_available("pipdeptree"):
            try:
                result = run_command(["pipdeptree"], check=False)
                if result.returncode == 0:
                    print(result.stdout)
                    return
            except FileNotFoundError:
                pass

        # Fallback to pip show with manual tree building
        print("  ⚠ pipdeptree not installed. Install with: pip install pipdeptree")
        print("  Falling back to pip list...\n")

        try:
            result = run_command(
                [sys.executable, "-m", "pip", "list", "--format=json"],
                check=False,
            )
            if result.returncode == 0:
                packages = json.loads(result.stdout)
                for pkg in sorted(packages, key=lambda p: p["name"].lower()):
                    print(f"  {pkg['name']}=={pkg['version']}")
        except (subprocess.CalledProcessError, json.JSONDecodeError):
            print("  ✗ Could not display dependency tree")

    def show_reverse_tree(self, package: str):
        """Show what depends on a specific package."""
        print(f"\n🔄 Reverse dependencies for {package}:")

        if check_tool_available("pipdeptree"):
            try:
                result = run_command(
                    ["pipdeptree", "--reverse", "--packages", package],
                    check=False,
                )
                if result.returncode == 0:
                    print(result.stdout)
                    return
            except FileNotFoundError:
                pass

        print("  ⚠ Install pipdeptree for reverse dependency tree: pip install pipdeptree")


# ============================================================================
# Main Dependency Manager (Orchestrator)
# ============================================================================

class DependencyManager:
    """
    Main orchestrator for dependency management operations.

    This class provides a unified interface across all backends and
    implements the team's dependency management best practices.
    """

    def __init__(self, project_dir: Optional[str] = None):
        self.project_dir = Path(project_dir) if project_dir else Path.cwd()
        self.config = load_config(self.project_dir)
        self.backend = self._get_backend()
        self.auditor = DependencyAuditor(self.project_dir, self.config)
        self.tree_viewer = DependencyTreeViewer(self.project_dir)

    def _get_backend(self):
        """Get the appropriate backend instance."""
        backends = {
            Backend.PIP_TOOLS: PipToolsBackend,
            Backend.POETRY: PoetryBackend,
            Backend.PIP: PipBackend,
        }
        backend_class = backends.get(self.config.backend, PipToolsBackend)
        return backend_class(self.project_dir, self.config)

    def init(self, backend_name: Optional[str] = None):
        """Initialize the project for dependency management."""
        if backend_name:
            self.config.backend = Backend(backend_name)
            self.backend = self._get_backend()

        self.config.python_version = get_python_version()
        self.config.project_name = self.project_dir.name

        print(f"🚀 Initializing dependency management")
        print(f"   Backend: {self.config.backend.value}")
        print(f"   Python: {self.config.python_version}")
        print(f"   Project: {self.config.project_name}")

        # Save configuration
        save_config(self.project_dir, self.config)

        # Initialize backend-specific files
        self.backend.init()

        # Create/update .gitignore recommendations
        self._update_gitignore()

        print("\n✅ Initialization complete!")
        print("\nNext steps:")
        print("  1. Edit your dependency source files to add packages")
        print("  2. Run: python dependency_manager.py lock")
        print("  3. Run: python dependency_manager.py install")
        print("  4. Commit lock files to version control")

    def lock(self):
        """Generate lock files from source dependency files."""
        print("🔒 Locking dependencies...")
        self.backend.lock()
        print("\n✅ Lock files generated. Commit them to version control!")

    def update(self, package: Optional[str] = None):
        """Update lock files, optionally for a specific package."""
        if package:
            print(f"📦 Updating {package}...")
        else:
            print("🔄 Updating all dependencies...")
        self.backend.update(package=package)
        print("\n✅ Update complete. Review changes and commit lock files.")

    def install(self, env: str = "dev"):
        """Install dependencies for the specified environment."""
        group_map = {
            "prod": [DependencyGroup.MAIN],
            "production": [DependencyGroup.MAIN],
            "dev": [DependencyGroup.MAIN, DependencyGroup.DEV],
            "development": [DependencyGroup.MAIN, DependencyGroup.DEV],
            "test": [DependencyGroup.MAIN, DependencyGroup.TEST],
            "all": [DependencyGroup.MAIN, DependencyGroup.DEV, DependencyGroup.TEST],
        }

        groups = group_map.get(env, [DependencyGroup.MAIN])
        print(f"📥 Installing for environment: {env}")
        print(f"   Groups: {', '.join(g.value for g in groups)}")
        self.backend.install(groups=groups)

    def add(self, package: str, group: str = "main"):
        """Add a new dependency."""
        dep_group = DependencyGroup(group)
        print(f"➕ Adding {package} to {dep_group.value}...")
        self.backend.add(package, dep_group)

    def remove(self, package: str, group: str = "main"):
        """Remove a dependency."""
        dep_group = DependencyGroup(group)
        print(f"➖ Removing {package} from {dep_group.value}...")
        self.backend.remove(package, dep_group)

    def audit(self):
        """Run dependency audit."""
        self.auditor.audit()

    def verify(self):
        """Verify lock file consistency."""
        if hasattr(self.backend, 'verify'):
            is_ok = self.backend.verify()
            if is_ok:
                print("\n✅ All lock files are consistent!")
            else:
                print("\n⚠️  Lock files need updating. Run 'lock' to fix.")
                sys.exit(1)

    def tree(self, package: Optional[str] = None):
        """Show dependency tree."""
        if package:
            self.tree_viewer.show_reverse_tree(package)
        else:
            self.tree_viewer.show_tree()

    def export(self, format: str = "requirements"):
        """Export lock file to a different format."""
        if isinstance(self.backend, PoetryBackend):
            if format == "requirements":
                self.backend.export()
            else:
                print(f"  ⚠ Export format '{format}' not supported for Poetry")
        else:
            print("  ℹ Export is primarily useful for Poetry → requirements.txt conversion")
            print("  Your lock files are already in requirements.txt format")

    def _update_gitignore(self):
        """Ensure .gitignore is properly configured."""
        gitignore = self.project_dir / ".gitignore"

        recommended_entries = [
            "# Virtual environments",
            "venv/",
            ".venv/",
            "env/",
            "",
            "# Python",
            "__pycache__/",
            "*.py[cod]",
            "*.egg-info/",
            "dist/",
            "build/",
            "",
            "# Dependency manager config (optional - may want to commit)",
            "# depmanager.json",
        ]

        # Lock files should NOT be in gitignore
        lock_warning = """
# ⚠ IMPORTANT: Do NOT gitignore lock files!
# Lock files (requirements.txt, poetry.lock) MUST be committed
# to ensure consistent builds across all environments.
"""

        if not gitignore.exists():
            content = "\n".join(recommended_entries) + "\n" + lock_warning
            gitignore.write_text(content)
            print(f"  ✓ Created {gitignore}")
        else:
            # Check if lock files are incorrectly ignored
            content = gitignore.read_text()
            warnings = []
            if self.config.backend == Backend.PIP_TOOLS:
                if "requirements.txt" in content:
                    warnings.append("requirements.txt is in .gitignore — lock files should be committed!")
            elif self.config.backend == Backend.POETRY:
                if "poetry.lock" in content:
                    warnings.append("poetry.lock is in .gitignore — lock files should be committed!")
            for w in warnings:
                print(f"  ⚠ {w}")


# ============================================================================
# Best Practices Documentation
# ============================================================================

BEST_PRACTICES = """
╔══════════════════════════════════════════════════════════════════════╗
║            DEPENDENCY MANAGEMENT BEST PRACTICES                     ║
╚══════════════════════════════════════════════════════════════════════╝

1. ALWAYS COMMIT LOCK FILES
   ─────────────────────────
   Lock files (requirements.txt, poetry.lock) ensure every developer,
   CI system, and production environment uses the exact same versions.

   ✓ DO commit: requirements.txt, requirements-dev.txt, poetry.lock
   ✗ DON'T commit: .in files changes without updating lock files

2. USE SEPARATE DEPENDENCY GROUPS
   ──────────────────────────────
   Keep production, development, and test dependencies separate:

   Production (requirements.in):
     - Only packages needed at runtime
     - These get deployed to production

   Development (requirements-dev.in):
     - Linters, formatters, debuggers
     - Includes production deps via: -r requirements.in

   Test (requirements-test.in):
     - Test frameworks and fixtures
     - Includes production deps via: -r requirements.in

3. PIN VERSIONS WITH CONSTRAINTS
   ─────────────────────────────
   In source files (.in), use loose constraints:
     requests>=2.28,<3.0    # Allow patches, prevent breaking changes
     django>=4.2,<5.0       # Stay within major version

   Lock files will pin exact versions:
     requests==2.31.0        # Exact version in lock file
     django==4.2.7           # Exact version in lock file

4. USE HASH VERIFICATION
   ─────────────────────
   Generate hashes in lock files to prevent supply-chain attacks:
     pip-compile --generate-hashes
     pip install --require-hashes -r requirements.txt

5. REGULAR UPDATES
   ───────────────
   Schedule regular dependency updates (weekly/monthly):
     python dependency_manager.py update           # Update all
     python dependency_manager.py update requests   # Update one

   Always run tests after updating!

6. AUDIT FOR VULNERABILITIES
   ─────────────────────────
   Regularly scan for known vulnerabilities:
     python dependency_manager.py audit
     pip-audit -r requirements.txt

7. CI/CD INTEGRATION
   ─────────────────
   In CI pipelines:
     - Use 'verify' to ensure lock files are current
     - Use 'install --env prod' for production deployments
     - Use 'install --env test' for running tests
     - Use 'audit' to check for vulnerabilities

   Example GitHub Actions step:
     - name: Verify dependencies
       run: python dependency_manager.py verify
     - name: Install dependencies
       run: python dependency_manager.py install --env test
     - name: Audit dependencies
       run: python dependency_manager.py audit

8. VIRTUAL ENVIRONMENTS
   ────────────────────
   Always use virtual environments:
     python -m venv .venv
     source .venv/bin/activate  # Linux/Mac
     .venv\\Scripts\\activate     # Windows

9. PYTHON VERSION PINNING
   ──────────────────────
   Specify the required Python version:
     - In pyproject.toml: python = "^3.10"
     - In .python-version: 3.10.12
     - In runtime.txt: python-3.10.12

10. WORKFLOW SUMMARY
    ───────────────
    Setup:
      python dependency_manager.py init --backend pip-tools

    Daily development:
      python dependency_manager.py add 'requests>=2.28'  # Add a dep
      python dependency_manager.py lock                    # Lock it
      git add requirements*.txt && git commit              # Commit

    Updating:
      python dependency_manager.py update                  # Update all
      python dependency_manager.py audit                   # Check security
      # Run tests!
      git add requirements*.txt && git commit              # Commit

    CI/Production:
      python dependency_manager.py verify                  # Check lock files
      python dependency_manager.py install --env prod      # Install
"""


